"use client";

import { useState } from "react";

interface JustificationProps {
  recommendations: any[];
}

function ScoreBar({ label, value, weight }: { label: string; value: number; weight: string }) {
  const pct = Math.round(value * 100);
  const color = value >= 0.7 ? "bg-green-500" : value >= 0.5 ? "bg-yellow-500" : "bg-red-500";

  return (
    <div className="flex items-center gap-2 text-xs">
      <span className="w-32 text-[var(--text-muted)] shrink-0">{label} ({weight})</span>
      <div className="flex-1 h-2 bg-[var(--bg-primary)] rounded-full overflow-hidden">
        <div className={`h-full rounded-full ${color}`} style={{ width: `${pct}%` }} />
      </div>
      <span className="font-mono w-10 text-right text-[var(--text-secondary)]">{(value * 10).toFixed(1)}</span>
    </div>
  );
}

function BenchmarkPills({ citations }: { citations: string[] }) {
  return (
    <div className="flex flex-wrap gap-1.5">
      {citations.map((c, i) => (
        <span
          key={i}
          className="inline-block px-2 py-0.5 bg-[var(--accent)]/15 text-[var(--accent-hover)] text-[10px] font-mono rounded-full border border-[var(--accent)]/20"
        >
          {c}
        </span>
      ))}
    </div>
  );
}

function CostBadge({ cost }: { cost: any }) {
  return (
    <div className="bg-[var(--bg-primary)] rounded-lg p-3 border border-[var(--border)]">
      <div className="flex items-center justify-between">
        <div>
          <div className="text-[10px] text-[var(--text-muted)] uppercase tracking-wide">Costo estimado</div>
          <div className="text-lg font-mono font-bold text-[var(--text-primary)]">{cost.estimated_monthly}</div>
        </div>
        <div className="text-right">
          <span className="px-2 py-0.5 bg-[var(--bg-secondary)] text-[var(--text-muted)] text-[10px] rounded-full">
            {cost.pricing_model}
          </span>
        </div>
      </div>
      <div className="text-[10px] text-[var(--text-muted)] mt-1">{cost.explanation}</div>
    </div>
  );
}

function HeadToHeadSection({ h2h }: { h2h: any }) {
  if (!h2h) return null;

  return (
    <div className="space-y-3">
      <div className="text-xs font-medium text-[var(--text-muted)]">
        Head-to-Head: {h2h.winner.tool_name} vs {h2h.runner_up.tool_name}
      </div>

      {/* Benchmark comparison table */}
      {h2h.benchmarks.length > 0 && (
        <div className="bg-[var(--bg-primary)] rounded-lg overflow-hidden border border-[var(--border)]">
          <table className="w-full text-xs">
            <thead>
              <tr className="border-b border-[var(--border)]">
                <th className="text-left py-2 px-3 text-[var(--text-muted)] font-medium">Benchmark</th>
                <th className="text-center py-2 px-3 text-green-400 font-medium">{h2h.winner.tool_name}</th>
                <th className="text-center py-2 px-3 text-[var(--text-muted)] font-medium">{h2h.runner_up.tool_name}</th>
              </tr>
            </thead>
            <tbody>
              {h2h.benchmarks.map((b: any, i: number) => (
                <tr key={i} className="border-b border-[var(--border)] last:border-0">
                  <td className="py-1.5 px-3 text-[var(--text-secondary)]">{b.benchmark_name}</td>
                  <td className="py-1.5 px-3 text-center font-mono font-bold text-green-400">{b.winner_value}</td>
                  <td className="py-1.5 px-3 text-center font-mono text-[var(--text-muted)]">{b.runner_up_value}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Verdict */}
      <div className="text-xs text-[var(--text-secondary)] italic bg-[var(--bg-secondary)] rounded p-2">
        {h2h.verdict}
      </div>
    </div>
  );
}

function TradeOffs({ tradeOffs }: { tradeOffs: string[] }) {
  if (!tradeOffs || tradeOffs.length === 0) return null;

  return (
    <div>
      <div className="text-xs font-medium text-[var(--text-muted)] mb-1">Trade-offs</div>
      <ul className="space-y-1">
        {tradeOffs.map((t, i) => (
          <li key={i} className="text-xs text-yellow-400/80 flex items-start gap-1.5">
            <span className="mt-0.5 shrink-0">~</span>
            <span>{t}</span>
          </li>
        ))}
      </ul>
    </div>
  );
}

function EvidenceSection({ evidence, papers }: { evidence: any[]; papers: any[] }) {
  return (
    <div className="space-y-3 mt-3">
      {evidence && evidence.length > 0 && (
        <div>
          <div className="text-xs font-medium text-[var(--text-muted)] mb-1">Fuentes oficiales</div>
          {evidence.map((ev: any, i: number) => (
            <a
              key={i}
              href={ev.url}
              target="_blank"
              rel="noopener noreferrer"
              className="block text-xs text-[var(--text-secondary)] hover:text-[var(--accent-hover)] mb-1"
            >
              <span className="inline-block px-1.5 py-0.5 bg-[var(--bg-primary)] rounded text-[10px] text-[var(--text-muted)] mr-1">
                {ev.type === "technical_report" ? "INFORME" : ev.type === "case_study" ? "CASO" : ev.type === "best_practices" ? "GUIA" : "DOC"}
              </span>
              {ev.title} — {ev.key_data}
            </a>
          ))}
        </div>
      )}

      {papers && papers.length > 0 && (
        <div>
          <div className="text-xs font-medium text-[var(--text-muted)] mb-1">Investigacion academica</div>
          {papers.map((paper: any, i: number) => (
            <a
              key={i}
              href={paper.url}
              target="_blank"
              rel="noopener noreferrer"
              className="block text-xs mb-2 hover:bg-[var(--bg-secondary)] rounded p-1.5 -mx-1.5"
            >
              <div className="flex items-center gap-1 mb-0.5">
                <span className={`inline-block px-1.5 py-0.5 rounded text-[10px] font-medium ${
                  paper.type === "peer_reviewed"
                    ? "bg-green-900/50 text-green-400"
                    : "bg-yellow-900/50 text-yellow-400"
                }`}>
                  {paper.type === "peer_reviewed" ? "PEER-REVIEWED" : "PREPRINT"}
                </span>
                <span className="text-[var(--text-muted)]">{paper.venue}</span>
              </div>
              <div className="text-[var(--text-secondary)] font-medium">{paper.title}</div>
              <div className="text-[var(--text-muted)] mt-0.5">{paper.key_finding}</div>
            </a>
          ))}
        </div>
      )}
    </div>
  );
}

export default function Justification({ recommendations }: JustificationProps) {
  const [openIndex, setOpenIndex] = useState<number | null>(null);

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold">Justificacion Tecnica</h2>

      <div className="space-y-2">
        {recommendations.map((rec, i) => {
          const t = rec.recommended_tool;
          const b = t.score_breakdown;
          const ej = t.enhanced_justification;
          const isOpen = openIndex === i;

          return (
            <div
              key={i}
              className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg overflow-hidden"
            >
              {/* Header - clickable */}
              <button
                onClick={() => setOpenIndex(isOpen ? null : i)}
                className="w-full flex items-center justify-between p-4 text-left hover:bg-[var(--bg-secondary)]"
              >
                <div className="flex items-center gap-3 min-w-0">
                  <span className="text-sm text-[var(--text-muted)] shrink-0">{rec.capability_name}</span>
                  <span className="text-sm font-semibold text-[var(--accent-hover)] truncate">{t.tool.name}</span>
                  {ej?.cost_estimate && (
                    <span className="hidden sm:inline-block px-2 py-0.5 bg-[var(--bg-secondary)] text-[10px] text-[var(--text-muted)] rounded-full font-mono shrink-0">
                      {ej.cost_estimate.estimated_monthly}
                    </span>
                  )}
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <span className="font-mono text-sm font-bold">{(t.final_score * 10).toFixed(1)}/10</span>
                  <svg
                    className={`w-4 h-4 text-[var(--text-muted)] transition-transform ${isOpen ? "rotate-180" : ""}`}
                    fill="none" stroke="currentColor" viewBox="0 0 24 24"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </div>
              </button>

              {/* Content - expandable */}
              {isOpen && (
                <div className="px-4 pb-4 border-t border-[var(--border)] pt-3 space-y-4">
                  {/* Summary */}
                  {ej?.summary && (
                    <div className="text-sm text-[var(--text-secondary)]">{ej.summary}</div>
                  )}

                  {/* Benchmark pills */}
                  {ej?.benchmark_citations && ej.benchmark_citations.length > 0 && (
                    <BenchmarkPills citations={ej.benchmark_citations} />
                  )}

                  {/* Cost estimate */}
                  {ej?.cost_estimate && (
                    <CostBadge cost={ej.cost_estimate} />
                  )}

                  {/* Head-to-head */}
                  {ej?.head_to_head && (
                    <HeadToHeadSection h2h={ej.head_to_head} />
                  )}

                  {/* Score bars */}
                  <div className="space-y-2">
                    <div className="text-xs font-medium text-[var(--text-muted)]">Score Breakdown</div>
                    <ScoreBar label="Calidad" value={b.quality} weight="40%" />
                    <ScoreBar label="Fit con proyecto" value={b.task_fit} weight="25%" />
                    <ScoreBar label="Nivel developer" value={b.dev_level} weight="15%" />
                    <ScoreBar label="Costo" value={b.cost} weight="10%" />
                    <ScoreBar label="Compatibilidad" value={b.compatibility} weight="10%" />
                  </div>

                  {/* Fit explanation */}
                  {ej?.fit_explanation && (
                    <div className="text-xs text-[var(--text-secondary)] bg-[var(--bg-secondary)] rounded p-2">
                      {ej.fit_explanation}
                    </div>
                  )}

                  {/* Trade-offs */}
                  <TradeOffs tradeOffs={ej?.trade_offs} />

                  {/* Strengths */}
                  <div>
                    <div className="text-xs font-medium text-[var(--text-muted)] mb-1">Fortalezas</div>
                    <ul className="text-xs text-[var(--text-secondary)] space-y-0.5">
                      {t.tool.strengths.map((s: string, j: number) => (
                        <li key={j}>+ {s}</li>
                      ))}
                    </ul>
                  </div>

                  {/* Weaknesses */}
                  {t.tool.weaknesses.length > 0 && (
                    <div>
                      <div className="text-xs font-medium text-[var(--text-muted)] mb-1">Consideraciones</div>
                      <ul className="text-xs text-[var(--text-secondary)] space-y-0.5">
                        {t.tool.weaknesses.map((w: string, j: number) => (
                          <li key={j} className="text-yellow-400/80">- {w}</li>
                        ))}
                      </ul>
                    </div>
                  )}

                  {/* Evidence + Papers */}
                  <EvidenceSection evidence={rec.evidence || []} papers={rec.papers || []} />
                </div>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}
