"use client";

import { useState } from "react";

interface AdvisorFormProps {
  onSubmit: (data: { prompt: string; developer_level: string; budget: string }) => void;
  isLoading: boolean;
}

export default function AdvisorForm({ onSubmit, isLoading }: AdvisorFormProps) {
  const [prompt, setPrompt] = useState("");
  const [level, setLevel] = useState("mid");
  const [budget, setBudget] = useState("medium");

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim()) return;
    onSubmit({ prompt, developer_level: level, budget });
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      {/* Prompt */}
      <div>
        <label htmlFor="prompt" className="block text-sm font-medium text-[var(--text-secondary)] mb-2">
          Describe tu proyecto
        </label>
        <textarea
          id="prompt"
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="Ej: Necesito crear un SaaS de gestion de inventario con dashboard, auth, pagos con Stripe y API REST..."
          rows={4}
          className="w-full px-4 py-3 bg-[var(--bg-secondary)] border border-[var(--border)] rounded-lg text-[var(--text-primary)] placeholder-[var(--text-muted)] focus:outline-none focus:border-[var(--accent)] focus:ring-1 focus:ring-[var(--accent)] resize-none"
          disabled={isLoading}
        />
      </div>

      {/* Level + Budget row */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div>
          <label htmlFor="level" className="block text-sm font-medium text-[var(--text-secondary)] mb-2">
            Tu nivel
          </label>
          <select
            id="level"
            value={level}
            onChange={(e) => setLevel(e.target.value)}
            className="w-full px-4 py-3 bg-[var(--bg-secondary)] border border-[var(--border)] rounded-lg text-[var(--text-primary)] focus:outline-none focus:border-[var(--accent)]"
            disabled={isLoading}
          >
            <option value="junior">Junior</option>
            <option value="mid">Mid-level</option>
            <option value="senior">Senior</option>
          </select>
        </div>
        <div>
          <label htmlFor="budget" className="block text-sm font-medium text-[var(--text-secondary)] mb-2">
            Presupuesto
          </label>
          <select
            id="budget"
            value={budget}
            onChange={(e) => setBudget(e.target.value)}
            className="w-full px-4 py-3 bg-[var(--bg-secondary)] border border-[var(--border)] rounded-lg text-[var(--text-primary)] focus:outline-none focus:border-[var(--accent)]"
            disabled={isLoading}
          >
            <option value="free">Gratis</option>
            <option value="low">Bajo</option>
            <option value="medium">Medio</option>
            <option value="unlimited">Sin limite</option>
          </select>
        </div>
      </div>

      {/* Submit */}
      <button
        type="submit"
        disabled={isLoading || !prompt.trim()}
        className="w-full py-3 px-6 bg-[var(--accent)] hover:bg-[var(--accent-hover)] disabled:opacity-40 disabled:cursor-not-allowed text-white font-medium rounded-lg transition-colors"
      >
        {isLoading ? "Analizando tu proyecto..." : "Analizar proyecto"}
      </button>
    </form>
  );
}
